Addressable sistemi, Unity'de asset yönetiminin geleceğidir. Ben tüm büyük projelerimde kullanırım:

```csharp
using UnityEngine.AddressableAssets;
using UnityEngine.ResourceManagement.AsyncOperations;

public class AssetLoader : MonoBehaviour
{
    private Dictionary<string, AsyncOperationHandle> loadedAssets = new();

    public async Task<T> LoadAsset<T>(string key) where T : UnityEngine.Object
    {
        if (loadedAssets.TryGetValue(key, out var handle))
            return (T)handle.Result;

        var op = Addressables.LoadAssetAsync<T>(key);
        var result = await op.Task;
        loadedAssets[key] = op;
        return result;
    }

    public void UnloadAsset(string key)
    {
        if (loadedAssets.TryGetValue(key, out var handle))
        {
            Addressables.Release(handle);
            loadedAssets.Remove(key);
        }
    }

    private void OnDestroy()
    {
        foreach (var handle in loadedAssets.Values)
            Addressables.Release(handle);
        loadedAssets.Clear();
    }
}
```

